import React, { Component, useState } from 'react';
import ReactDOM from 'react-dom/client';

 
async function Read() {

    const docRef = doc(db, "City", "Leuven");
    const docSnap = await getDoc(docRef);
    
    
    const idArray = []
    const testArray = []
    if (docSnap.exists()) {
